options.script:
// --- helpers ---
const s = data.series[0];
const fields = s.fields || [];
const byName = Object.fromEntries(fields.map(f => [f.name, f]));
const vals = (name) => byName[name]?.values?.buffer ?? byName[name]?.values ?? [];

// Expect aliases from SQL: time, x, y, z
const tRaw = vals("time");
const x = Array.from(vals("x"));
const y = Array.from(vals("y"));
const z = Array.from(vals("z"));

// Convert time values to epoch ms (for colors + hover)
const tMs = Array.from(tRaw).map(v => {
  if (v instanceof Date) return v.getTime();
  const n = Number(v);
  if (Number.isFinite(n) && n > 1e11) return n; // already ms
  return new Date(v).getTime();
});

// Optional: break the line if there is a long gap (avoids drawing a line across outages)
// Set to Infinity to always connect consecutive points.
const MAX_GAP_MS = Infinity; // e.g. 10 * 60 * 1000 for 10 minutes

// Build line arrays (with null breaks if gap > MAX_GAP_MS)
const lx = [];
const ly = [];
const lz = [];
for (let i = 0; i < x.length; i++) {
  if (i > 0 && (tMs[i] - tMs[i - 1]) > MAX_GAP_MS) {
    lx.push(null); ly.push(null); lz.push(null);
  }
  lx.push(x[i]); ly.push(y[i]); lz.push(z[i]);
}

// Time-based blue fade (old -> transparent blue, new -> solid blue)
const tMin = Math.min(...tMs);
const tMax = Math.max(...tMs);
const blueFade = [
  [0.0, "rgba(30, 144, 255, 0.08)"], // old
  [1.0, "rgba(30, 144, 255, 1.00)"]  // new
];

return {
  data: [
    // Thin connecting line
    {
      type: "scatter3d",
      mode: "lines",
      x: lx,
      y: ly,
      z: lz,
      line: {
        width: 1,
        color: "rgba(120,120,120,0.35)"
      },
      hoverinfo: "skip",
      showlegend: false
    },

    // Markers with time gradient
    {
      type: "scatter3d",
      mode: "markers",
      x: x,
      y: y,
      z: z,
      text: tMs.map(ms => new Date(ms).toLocaleString()),
      hovertemplate:
        "X: %{x:.3f}<br>" +
        "Y: %{y:.3f}<br>" +
        "Z: %{z:.3f}<br>" +
        "Time: %{text}<extra></extra>",
      marker: {
        size: 2,
        color: tMs,          // numeric array -> colorscale
        cmin: tMin,
        cmax: tMax,
        colorscale: blueFade,
        showscale: false     // set true if you want a time colorbar
      },
      name: "accel0"
    }
  ],

  layout: {
    title: "Accelerometer 0 (3D trail)",
    margin: { l: 0, r: 0, b: 0, t: 28 },
    scene: {
      xaxis: { title: "X" },
      yaxis: { title: "Y" },
      zaxis: { title: "Z" }
    },
    // keeps camera position when panel refreshes
    uirevision: "accel3d"
  },

  config: {
    displayModeBar: true
  }
};

