options.script:
// nLine PlotlyJS panel script (Grafana)
// Assumes query returns columns: time, x, y, z

function getField(frame, name) {
  const f = frame.fields.find(ff => ff.name === name);
  if (!f) throw new Error(`Field not found: ${name}`);
  const v = f.values;
  if (Array.isArray(v)) return v;
  if (typeof v.toArray === "function") return v.toArray();
  // Grafana vectors sometimes expose get(i)
  const out = [];
  for (let i = 0; i < v.length; i++) out.push(v.get(i));
  return out;
}

function median(arr) {
  const a = arr.filter(v => Number.isFinite(v)).slice().sort((m, n) => m - n);
  const n = a.length;
  if (!n) return NaN;
  const mid = Math.floor(n / 2);
  return n % 2 ? a[mid] : 0.5 * (a[mid - 1] + a[mid]);
}

function mean(arr) {
  let s = 0, n = 0;
  for (const v of arr) if (Number.isFinite(v)) { s += v; n++; }
  return n ? s / n : NaN;
}

function norm(v) {
  return Math.sqrt(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]);
}

function normalize(v) {
  const n = norm(v);
  if (!n) return [0, 0, 0];
  return [v[0]/n, v[1]/n, v[2]/n];
}

function dot(a, b) {
  return a[0]*b[0] + a[1]*b[1] + a[2]*b[2];
}

function mul(v, s) {
  return [v[0]*s, v[1]*s, v[2]*s];
}

function add(a, b) {
  return [a[0]+b[0], a[1]+b[1], a[2]+b[2]];
}

function sub(a, b) {
  return [a[0]-b[0], a[1]-b[1], a[2]-b[2]];
}

// Power iteration for dominant eigenvector of 3x3 symmetric matrix
function dominantEigenvector3(C, iters = 50) {
  let v = [1, 1, 1];
  v = normalize(v);

  for (let k = 0; k < iters; k++) {
    const w = [
      C[0][0]*v[0] + C[0][1]*v[1] + C[0][2]*v[2],
      C[1][0]*v[0] + C[1][1]*v[1] + C[1][2]*v[2],
      C[2][0]*v[0] + C[2][1]*v[1] + C[2][2]*v[2],
    ];
    const nw = norm(w);
    if (!nw) break;
    v = [w[0]/nw, w[1]/nw, w[2]/nw];
  }

  // Rayleigh quotient for eigenvalue
  const Cv = [
    C[0][0]*v[0] + C[0][1]*v[1] + C[0][2]*v[2],
    C[1][0]*v[0] + C[1][1]*v[1] + C[1][2]*v[2],
    C[2][0]*v[0] + C[2][1]*v[1] + C[2][2]*v[2],
  ];
  const lambda = dot(v, Cv);

  return { v, lambda };
}

const frame = data.series[0];
const x = getField(frame, "x");
const y = getField(frame, "y");
const z = getField(frame, "z");

// Filter valid rows
const pts = [];
for (let i = 0; i < x.length; i++) {
  const xi = Number(x[i]), yi = Number(y[i]), zi = Number(z[i]);
  if (Number.isFinite(xi) && Number.isFinite(yi) && Number.isFinite(zi)) {
    pts.push([xi, yi, zi]);
  }
}

if (!pts.length) {
  return {
    data: [],
    layout: { title: { text: "No accelerometer data" } }
  };
}

// Robust center (median)
const cx = median(pts.map(p => p[0]));
const cy = median(pts.map(p => p[1]));
const cz = median(pts.map(p => p[2]));
const c = [cx, cy, cz];

// Centered points
const q = pts.map(p => sub(p, c));

// Covariance matrix (centered)
let sxx=0, sxy=0, sxz=0, syy=0, syz=0, szz=0;
for (const p of q) {
  sxx += p[0]*p[0];
  sxy += p[0]*p[1];
  sxz += p[0]*p[2];
  syy += p[1]*p[1];
  syz += p[1]*p[2];
  szz += p[2]*p[2];
}
const n = q.length || 1;
const C = [
  [sxx/n, sxy/n, sxz/n],
  [sxy/n, syy/n, syz/n],
  [sxz/n, syz/n, szz/n],
];

// PCA dominant vector (PC1)
let { v: pc1, lambda: pc1Var } = dominantEigenvector3(C);

// Gravity direction from center (accelerometer static vector)
// center ≈ measured gravity direction in sensor frame
let gDir = normalize(c);

// Make PC1 point roughly same half-space as gravity for easier comparison
if (dot(pc1, gDir) < 0) pc1 = mul(pc1, -1);

// RMS stats using gravity direction
let sumUp2 = 0;
let sumH2 = 0;
for (const p of q) {
  const up = dot(p, gDir); // component along gravity
  const pPar = mul(gDir, up);
  const pHor = sub(p, pPar);
  const h2 = dot(pHor, pHor);

  sumUp2 += up * up;
  sumH2 += h2;
}
const rmsUp = Math.sqrt(sumUp2 / n);
const rmsH = Math.sqrt(sumH2 / n);
const ratio = rmsH > 0 ? (rmsUp / rmsH) : null;

// Angle between PCA dominant direction and gravity axis (acute angle)
const cosAng = Math.min(1, Math.max(-1, Math.abs(dot(pc1, gDir))));
const angleDeg = Math.acos(cosAng) * 180 / Math.PI;

// Build overlay line lengths
const devNorms = q.map(p => norm(p));
const maxDev = Math.max(...devNorms, 0.01);

// Gravity line through center
const gA = sub(c, mul(gDir, maxDev));
const gB = add(c, mul(gDir, maxDev));

// PCA line through center
const pA = sub(c, mul(pc1, maxDev));
const pB = add(c, mul(pc1, maxDev));

// To avoid misleading perspective, force equal scaling around the cloud
const allX = pts.map(p => p[0]);
const allY = pts.map(p => p[1]);
const allZ = pts.map(p => p[2]);

const minX = Math.min(...allX), maxX = Math.max(...allX);
const minY = Math.min(...allY), maxY = Math.max(...allY);
const minZ = Math.min(...allZ), maxZ = Math.max(...allZ);

const rx = maxX - minX, ry = maxY - minY, rz = maxZ - minZ;
const r = Math.max(rx, ry, rz) * 0.6 || 0.1;

const centerPlot = [
  0.5 * (minX + maxX),
  0.5 * (minY + maxY),
  0.5 * (minZ + maxZ)
];

const traces = [
  {
    type: "scatter3d",
    mode: "markers",
    name: "Raw accel0",
    x: pts.map(p => p[0]),
    y: pts.map(p => p[1]),
    z: pts.map(p => p[2]),
    marker: { size: 3 }
  },
  {
    type: "scatter3d",
    mode: "lines",
    name: "Gravity axis",
    x: [gA[0], gB[0]],
    y: [gA[1], gB[1]],
    z: [gA[2], gB[2]],
    line: { width: 6 }
  },
  {
    type: "scatter3d",
    mode: "lines",
    name: "PCA dominant axis",
    x: [pA[0], pB[0]],
    y: [pA[1], pB[1]],
    z: [pA[2], pB[2]],
    line: { width: 6, dash: "dot" }
  },
  {
    type: "scatter3d",
    mode: "markers",
    name: "Center",
    x: [c[0]],
    y: [c[1]],
    z: [c[2]],
    marker: { size: 5, symbol: "diamond" }
  }
];

const interpretation = (ratio !== null && Number.isFinite(ratio))
  ? (ratio > 1 ? "vertical-dominant" : "sideways-dominant")
  : "n/a";

const layout = {
  title: {
    text: "Raw accelerometer cloud + Gravity + PCA",
    x: 0.02
  },
  margin: { l: 0, r: 0, t: 50, b: 0 },
  scene: {
    xaxis: { title: "X", range: [centerPlot[0]-r, centerPlot[0]+r] },
    yaxis: { title: "Y", range: [centerPlot[1]-r, centerPlot[1]+r] },
    zaxis: { title: "Z", range: [centerPlot[2]-r, centerPlot[2]+r] },
    aspectmode: "cube"
  },
  annotations: [
    {
      x: 0.01, y: 0.99, xref: "paper", yref: "paper",
      xanchor: "left", yanchor: "top",
      showarrow: false,
      align: "left",
      text:
        `rms_up=${rmsUp.toFixed(5)}<br>` +
        `rms_horizontal=${rmsH.toFixed(5)}<br>` +
        `ratio=${ratio !== null ? ratio.toFixed(3) : "n/a"} (${interpretation})<br>` +
        `PCA↔gravity angle=${angleDeg.toFixed(1)}°`
    }
  ],
  legend: { orientation: "h" }
};

return {
  data: traces,
  layout: layout,
  config: { responsive: true }
};

