options.script:
// =========================
// Raw Accelerometer XYZ in 3D (no normalization / no rotation)
// =========================

if (!data?.series?.length) {
  return { data: [], layout: { title: "No data" } };
}

const s = data.series[0];
const fields = s.fields || [];
const byName = Object.fromEntries(fields.map(f => [f.name, f]));
const vals = (name) => byName[name]?.values?.buffer ?? byName[name]?.values ?? [];

// ---- Config ----
const MAX_GAP_MS = Infinity;   // set e.g. 10*60*1000 to break lines on long gaps
const MARKER_SIZE = 2;
const LINE_WIDTH = 1;
const SHOW_COLORBAR = false;
const FORCE_EQUAL_AXIS_RANGE = true; // same numeric scale on X/Y/Z

// ---- Helpers ----
const arrVals = (v) => Array.from(v ?? []);
const num = (v) => Number(v);
const finite = (v) => Number.isFinite(v);

// ---- Read rows ----
const tRaw = arrVals(vals("time"));
const xRaw = arrVals(vals("x"));
const yRaw = arrVals(vals("y"));
const zRaw = arrVals(vals("z"));

const rows = [];
const n = Math.min(tRaw.length, xRaw.length, yRaw.length, zRaw.length);

for (let i = 0; i < n; i++) {
  const x = num(xRaw[i]);
  const y = num(yRaw[i]);
  const z = num(zRaw[i]);
  if (!finite(x) || !finite(y) || !finite(z)) continue;

  let t;
  const tv = tRaw[i];
  if (tv instanceof Date) {
    t = tv.getTime();
  } else {
    const tn = Number(tv);
    t = (finite(tn) && tn > 1e11) ? tn : new Date(tv).getTime();
  }
  if (!finite(t)) continue;

  rows.push({ t, x, y, z });
}

if (!rows.length) {
  return { data: [], layout: { title: "No valid rows" } };
}

rows.sort((a, b) => a.t - b.t);

const tMs = rows.map(r => r.t);
const x = rows.map(r => r.x);
const y = rows.map(r => r.y);
const z = rows.map(r => r.z);

// ---- Line arrays with optional gap breaks ----
const lx = [], ly = [], lz = [];
for (let i = 0; i < rows.length; i++) {
  if (i > 0 && finite(MAX_GAP_MS) && (rows[i].t - rows[i - 1].t) > MAX_GAP_MS) {
    lx.push(null); ly.push(null); lz.push(null);
  }
  lx.push(rows[i].x);
  ly.push(rows[i].y);
  lz.push(rows[i].z);
}

// ---- Time gradient ----
let tMin = Math.min(...tMs);
let tMax = Math.max(...tMs);
if (tMax === tMin) tMax = tMin + 1;

const blueFade = [
  [0.0, "rgba(30,144,255,0.08)"],
  [1.0, "rgba(30,144,255,1.00)"]
];

// ---- Hover text ----
const hoverText = rows.map(r =>
  `${new Date(r.t).toLocaleString()}<br>` +
  `X: ${r.x}<br>` +
  `Y: ${r.y}<br>` +
  `Z: ${r.z}`
);

// ---- Equal numeric range on all axes (optional) ----
let sceneAxes = {
  xaxis: { title: "X" },
  yaxis: { title: "Y" },
  zaxis: { title: "Z" }
};

if (FORCE_EQUAL_AXIS_RANGE) {
  const all = [...x, ...y, ...z].filter(finite);
  let minV = Math.min(...all);
  let maxV = Math.max(...all);

  if (!finite(minV) || !finite(maxV)) {
    minV = -1;
    maxV = 1;
  }

  // small padding
  const pad = (maxV - minV) * 0.05 || 0.01;
  const lo = minV - pad;
  const hi = maxV + pad;

  sceneAxes = {
    xaxis: { title: "X", range: [lo, hi] },
    yaxis: { title: "Y", range: [lo, hi] },
    zaxis: { title: "Z", range: [lo, hi] }
  };
}

return {
  data: [
    // thin connecting line
    {
      type: "scatter3d",
      mode: "lines",
      x: lx,
      y: ly,
      z: lz,
      line: { width: LINE_WIDTH, color: "rgba(150,150,150,0.35)" },
      hoverinfo: "skip",
      showlegend: false
    },

    // time-colored dots
    {
      type: "scatter3d",
      mode: "markers",
      x,
      y,
      z,
      text: hoverText,
      hovertemplate: "%{text}<extra></extra>",
      marker: {
        size: MARKER_SIZE,
        color: tMs,
        cmin: tMin,
        cmax: tMax,
        colorscale: blueFade,
        showscale: SHOW_COLORBAR
      },
      name: "raw accel"
    }
  ],

  layout: {
    title: "Accelerometer 0 (raw X/Y/Z)",
    margin: { l: 0, r: 0, b: 0, t: 30 },
    uirevision: "accel3d-raw-xyz",
    scene: {
      aspectmode: "cube",
      ...sceneAxes
    }
  },

  config: {
    displayModeBar: true
  }
};

