options.script:
// =========================
// Orientation Helper Panel
// Shows estimated gravity/orientation vector from avg accel (gx,gy,gz)
// =========================

if (!data?.series?.length) {
  return { data: [], layout: { title: "No data" } };
}

const s = data.series[0];
const fields = s.fields || [];
const byName = Object.fromEntries(fields.map(f => [f.name, f]));
const vals = (name) => byName[name]?.values?.buffer ?? byName[name]?.values ?? [];

const gxArr = Array.from(vals("gx"));
const gyArr = Array.from(vals("gy"));
const gzArr = Array.from(vals("gz"));

const gx = Number(gxArr[0]);
const gy = Number(gyArr[0]);
const gz = Number(gzArr[0]);

if (![gx, gy, gz].every(Number.isFinite)) {
  return { data: [], layout: { title: "No valid orientation values" } };
}

const mag = Math.hypot(gx, gy, gz) || 1;
const ux = gx / mag;
const uy = gy / mag;
const uz = gz / mag;

// Dominant raw axis label (quick human-readable mounting hint)
const comps = [
  { axis: "X", v: ux },
  { axis: "Y", v: uy },
  { axis: "Z", v: uz }
].sort((a, b) => Math.abs(b.v) - Math.abs(a.v));

const dominant = `${comps[0].axis}${comps[0].v >= 0 ? "+" : "-"}`;

// Build simple axis guide lines
const axisLen = 1.0;

return {
  data: [
    // X axis guide
    {
      type: "scatter3d",
      mode: "lines",
      x: [-axisLen, axisLen],
      y: [0, 0],
      z: [0, 0],
      line: { width: 3, color: "rgba(255,120,120,0.7)" },
      hoverinfo: "skip",
      showlegend: false
    },
    // Y axis guide
    {
      type: "scatter3d",
      mode: "lines",
      x: [0, 0],
      y: [-axisLen, axisLen],
      z: [0, 0],
      line: { width: 3, color: "rgba(120,255,120,0.7)" },
      hoverinfo: "skip",
      showlegend: false
    },
    // Z axis guide
    {
      type: "scatter3d",
      mode: "lines",
      x: [0, 0],
      y: [0, 0],
      z: [-axisLen, axisLen],
      line: { width: 3, color: "rgba(120,180,255,0.7)" },
      hoverinfo: "skip",
      showlegend: false
    },

    // Orientation vector (gravity direction in sensor coords)
    {
      type: "scatter3d",
      mode: "lines+markers",
      x: [0, ux],
      y: [0, uy],
      z: [0, uz],
      line: { width: 8, color: "rgba(255,255,255,0.95)" },
      marker: {
        size: [2, 5],
        color: ["rgba(255,255,255,0.4)", "rgba(255,255,255,1)"]
      },
      text: [
